Code Good:
fn load_config() -> Result<Config, anyhow::Error> {
    let data = std::fs::read_to_string("config.toml")
        .context("failed to read config")?;
    let cfg = toml::from_str(&data)
        .context("invalid TOML")?;
    Ok(cfg)
}

