async fn handler() -> String {
    let data = tokio::fs::read_to_string("big.csv").await.unwrap();
    tokio::time::sleep(std::time::Duration::from_secs(1)).await;
    tokio::task::spawn_blocking(move || expensive_computation(&data)).await.unwrap()
}

