Code Good:
fn handle_error(err: AppError) {
    match err {
        AppError::NotFound => return_404(),
        AppError::Unauthorized => return_401(),
        AppError::Validation(msg) => return_400(msg),
        AppError::Internal(e) => {
            tracing::error!(error = %e, "internal error");
            return_500()
        }
    }
}

