Code Good:
struct Email(String);
impl Email {
    fn new(s: String) -> Result<Self, &'static str> {
        if s.contains('@') { Ok(Self(s)) } else { Err("invalid") }
    }
}
struct Age(u32);
impl Age {
    fn new(n: u32) -> Result<Self, &'static str> {
        if n <= 150 { Ok(Self(n)) } else { Err("invalid") }
    }
}
fn create_user(email: Email, age: Age) -> User {
    // already validated at construction
    User { email, age }
}

